  /* Check if UE has pending data in RLC buffers */
  NR_UE_sched_ctrl_t *sched_ctrl = &UE->UE_sched_ctrl;
  bool has_pending_data = false;

  for (int lcid = 0; lcid < MAX_NR_LCID; lcid++) {
    if (sched_ctrl->rlc_status[lcid].bytes_in_buffer > 0) {
      has_pending_data = true;
      LOG_D(NR_MAC, "UE RNTI 0x%04x has %d bytes pending on LCID %d after F1AP config\n",
            rnti, sched_ctrl->rlc_status[lcid].bytes_in_buffer, lcid);
    }
  }

  if (has_pending_data) {
    LOG_I(NR_MAC, "Triggering scheduler for UE RNTI 0x%04x with pending data after F1AP config\n", rnti);
    /* The scheduler will be triggered in the next slot, so we just log here */
    /* The actual scheduling will happen in gNB_dlsch_ulsch_scheduler() */
  }
}

