/* Trigger scheduler to check for pending data after UE context setup */
static void trigger_scheduler_after_f1ap_config(module_id_t module_id, rnti_t rnti)
{
  gNB_MAC_INST *gNB = RC.nrmac[module_id];
  if (!gNB) {
    LOG_E(NR_MAC, "gNB instance not found for module_id %d\n", module_id);
    return;
  }

  NR_UE_info_t *UE = find_nr_UE(&gNB->UE_info, rnti);
  if (!UE) {
    LOG_W(NR_MAC, "UE with RNTI 0x%04x not found after F1AP config\n", rnti);
    return;
  }

  /* Check if UE has pending data in RLC buffers */
  NR_UE_sched_ctrl_t *sched_ctrl = &UE->UE_sched_ctrl;
  bool has_pending_data = false;
